import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Wallet, ShoppingBag, CreditCard, 
  LayoutDashboard, Plus, TrendingUp, Users, User as UserIcon 
} from 'lucide-react';
import { Link } from 'react-router-dom';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0, totalCartoes: 0 });
  const [gastosPorUsuario, setGastosPorUsuario] = useState([]);
  const [perfil, setPerfil] = useState({ nome: 'Usuário', tipo: 'comum' });

  useEffect(() => {
    async function buscarDados() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfilData } = await supabase
        .from('profiles')
        .select('nome, tipo_usuario')
        .eq('id', user.id)
        .single();
      
      if (perfilData) setPerfil({ nome: perfilData.nome.split(' ')[0], tipo: perfilData.tipo_usuario });

      // Busca todas as compras para processar as parcelas do mês atual
      const { data: compras } = await supabase
        .from('compras')
        .select('*, profiles(nome)');

      const { data: cartoes } = await supabase.from('cartoes').select('id').eq('user_id', user.id);

      if (compras) {
        const agora = new Date();
        const mesAtual = agora.getMonth();
        const anoAtual = agora.getFullYear();

        let totalGeral = 0;
        let contagemItens = 0;
        const agrupado = {};

        compras.forEach(item => {
          const numParcelas = item.num_parcelas || 1;
          const valorParcela = parseFloat(item.valor_total) / numParcelas;

          for (let i = 0; i < numParcelas; i++) {
            const dataCompra = new Date(item.data_compra + 'T12:00:00');
            const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);

            if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
              // Verifica se o usuário pode ver este gasto
              const ehDono = item.user_id === user.id;
              const ehProprietario = perfilData?.tipo_usuario === 'proprietario';

              if (ehProprietario || ehDono) {
                totalGeral += valorParcela;
                contagemItens++;

                // Lógica de Nome: Prioridade para o Join, depois coluna texto
                const nomeResponsavel = item.profiles?.nome || item.responsavel || 'Outros';
                agrupado[nomeResponsavel] = (agrupado[nomeResponsavel] || 0) + valorParcela;
              }
            }
          }
        });

        setResumo({
          total: totalGeral,
          quantidade: contagemItens,
          totalCartoes: cartoes?.length || 0
        });

        setGastosPorUsuario(Object.keys(agrupado).map(nome => ({ nome, valor: agrupado[nome] })));
      }
    }
    buscarDados();
  }, []);

  const theme = { primary: '#4361ee', dark: '#0f172a', textMuted: '#64748b', surface: '#ffffff' };

  return (
    <div className="fade-in" style={{ padding: '25px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '100px' }}>
      <header style={{ marginBottom: '35px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <span style={{ color: theme.textMuted, fontSize: '0.8rem', fontWeight: 800, textTransform: 'uppercase' }}>Resumo Mensal</span>
          <h1 style={{ fontSize: '2rem', margin: '5px 0 0 0', fontWeight: 800, color: theme.dark }}>Olá, {perfil.nome} 👋</h1>
        </div>
      </header>

      <div style={mainCardStyle(theme)}>
        <div style={{ position: 'relative', zIndex: 2 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', opacity: 0.8, marginBottom: '10px' }}>
            <Wallet size={18} />
            <span style={{ fontSize: '0.9rem', fontWeight: 600 }}>Total de Dívidas (Mês Atual)</span>
          </div>
          <h2 style={{ fontSize: '3rem', margin: '10px 0', fontWeight: 900 }}>
            R$ {resumo.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </h2>

          {perfil.tipo === 'proprietario' && (
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px', marginTop: '20px' }}>
              {gastosPorUsuario.map((g, i) => (
                <div key={i} style={miniCardStyle}>
                  <span style={{ fontSize: '0.7rem', opacity: 0.8, fontWeight: 700 }}>{g.nome.split(' ')[0]}</span>
                  <span style={{ fontWeight: 800 }}>R$ {g.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                </div>
              ))}
            </div>
          )}

          <div style={{ display: 'flex', gap: '20px', marginTop: '25px', opacity: 0.9 }}>
            <small><b>{resumo.quantidade}</b> Lançamentos</small>
            <small><b>{resumo.totalCartoes}</b> Cartões Ativos</small>
          </div>
        </div>
      </div>

      <div style={gridStyle}>
        <QuickAction to="/dashboard" icon={<LayoutDashboard />} label="Painel" color={theme.primary} />
        <QuickAction to="/cartoes" icon={<CreditCard />} label="Cartões" color="#7209b7" />
        <QuickAction to="/listagem" icon={<ShoppingBag />} label="Extrato" color="#00cc66" />
        <QuickAction to="/lancamento" icon={<Plus />} label="Novo" color="#fff" bg={theme.primary} isPrimary />
      </div>
    </div>
  );
};

const QuickAction = ({ to, icon, label, color, bg = '#fff', isPrimary }) => (
  <Link to={to} style={{ textDecoration: 'none' }}>
    <div style={{ background: bg, padding: '20px', borderRadius: '24px', textAlign: 'center', color: isPrimary ? '#fff' : '#0f172a', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
      <div style={{ color: isPrimary ? '#fff' : color, marginBottom: '10px', display: 'flex', justifyContent: 'center' }}>{icon}</div>
      <span style={{ fontWeight: 800 }}>{label}</span>
    </div>
  </Link>
);

const mainCardStyle = (t) => ({ background: `linear-gradient(135deg, ${t.dark} 0%, #3f37c9 100%)`, borderRadius: '32px', padding: '35px', color: 'white', marginBottom: '35px', position: 'relative', overflow: 'hidden' });
const miniCardStyle = { background: 'rgba(255,255,255,0.15)', padding: '10px 15px', borderRadius: '15px', display: 'flex', flexDirection: 'column' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '15px' };

export default Menu;
